import subprocess
import re
from pathlib import Path
from typing import Dict, Any

class SecureFFmpegProcessor:
    UPLOAD_DIR = Path('/var/app/uploads')
    OUTPUT_DIR = Path('/var/app/output')

    ALLOWED_INPUT_FORMATS = {'mp4', 'avi', 'mov', 'mkv', 'webm'}
    ALLOWED_OUTPUT_FORMATS = {'mp4', 'webm', 'avi'}

    FILENAME_PATTERN = re.compile(r'^[a-zA-Z0-9_.-]{1,100}$')
    BITRATE_PATTERN = re.compile(r'^\d{3,5}k$')  # e.g., 1000k, 5000k

    @classmethod
    def validate_filename(cls, filename: str) -> Path:
        if not cls.FILENAME_PATTERN.match(filename):
            raise ValueError('Invalid filename format')

        ext = filename.rsplit('.', 1)[-1].lower()
        if ext not in cls.ALLOWED_INPUT_FORMATS:
            raise ValueError(f'Input format not allowed: {ext}')

        filepath = (cls.UPLOAD_DIR / filename).resolve()

        # Prevent path traversal
        if not str(filepath).startswith(str(cls.UPLOAD_DIR)):
            raise ValueError('Path traversal detected')

        if not filepath.exists():
            raise ValueError('File does not exist')

        return filepath

    @classmethod
    def validate_bitrate(cls, bitrate: str) -> str:
        if not cls.BITRATE_PATTERN.match(bitrate):
            raise ValueError('Invalid bitrate format')

        value = int(bitrate.rstrip('k'))
        if value < 100 or value > 50000:
            raise ValueError('Bitrate out of range (100k-50000k)')

        return bitrate

    @classmethod
    def convert_video(cls, input_filename: str, output_format: str, bitrate: str) -> Dict[str, Any]:
        try:
            # Validate inputs
            input_path = cls.validate_filename(input_filename)

            if output_format not in cls.ALLOWED_OUTPUT_FORMATS:
                raise ValueError(f'Output format not allowed: {output_format}')

            valid_bitrate = cls.validate_bitrate(bitrate)

            # Generate safe output filename
            import uuid
            output_filename = f"{uuid.uuid4()}.{output_format}"
            output_path = cls.OUTPUT_DIR / output_filename

            # Build FFmpeg command using argument list
            ffmpeg_args = [
                'ffmpeg',
                '-i', str(input_path),
                '-b:v', valid_bitrate,
                '-c:v', 'libx264',
                '-preset', 'medium',
                '-y',  # Overwrite output
                str(output_path)
            ]

            # Execute with subprocess (no shell)
            result = subprocess.run(
                ffmpeg_args,
                shell=False,
                capture_output=True,
                text=True,
                timeout=300,  # 5 minute timeout
                check=False
            )

            if result.returncode != 0:
                return {'success': False, 'error': 'Conversion failed'}

            return {
                'success': True,
                'output_file': output_filename,
                'path': str(output_path)
            }

        except ValueError as e:
            return {'success': False, 'error': str(e)}
        except subprocess.TimeoutExpired:
            return {'success': False, 'error': 'Processing timeout'}

